function safeStorageGet(storage, key) {
	try {
		return storage?.getItem(key) ?? null;
	} catch {
		return null;
	}
}

function safeStorageSet(storage, key, value) {
	try {
		storage?.setItem(key, value);
	} catch {
		// ignore
	}
}

export function hasNativeCapacitorBrowser(capacitorLike) {
	const capacitor =
		capacitorLike ??
		(typeof window !== "undefined" ? window?.Capacitor : null);
	return Boolean(
		capacitor?.isNativePlatform?.() && capacitor?.Plugins?.Browser,
	);
}

export function closeCapacitorBrowserSafely(browserLike) {
	if (!browserLike?.close) return Promise.resolve(false);
	return Promise.resolve()
		.then(() => browserLike.close())
		.then(() => true)
		.catch(() => false);
}

