function truncateLandingReviewQuote(value, maxLength = 220) {
	const text = String(value || "").trim().replace(/\s+/g, " ");
	if (!text) return "";
	if (text.length <= maxLength) return text;
	return `${text.slice(0, Math.max(0, maxLength - 1)).trimEnd()}…`;
}

function formatLandingReviewName(user) {
	const firstName =
		user?.firstName || user?.first_name || user?.first || user?.name || "";
	const lastName = user?.lastName || user?.last_name || user?.last || "";
	const trimmedFirst = String(firstName || "").trim();
	const trimmedLast = String(lastName || "").trim();
	if (trimmedFirst && trimmedLast) {
		return `${trimmedFirst} ${trimmedLast.charAt(0).toUpperCase()}.`;
	}
	if (trimmedFirst) return trimmedFirst;
	return "ErrandBridge client";
}

function formatLandingReviewRegion(errand) {
	if (!errand) return "ErrandBridge";
	if (Number(errand?.id) === -1) return "Website feedback";

	const pickupRegion =
		errand?.pickupRegion ||
		errand?.pickup_region ||
		errand?.pickupCity ||
		errand?.pickup_city ||
		errand?.pickupLocation ||
		errand?.pickup_location ||
		"";
	const dropoffRegion =
		errand?.dropoffRegion ||
		errand?.dropoff_region ||
		errand?.dropoffCity ||
		errand?.dropoff_city ||
		errand?.dropoffLocation ||
		errand?.dropoff_location ||
		"";
	const routeLabel = [pickupRegion, dropoffRegion]
		.map((value) => String(value || "").trim())
		.filter(Boolean)
		.join(" → ");
	if (routeLabel) return routeLabel;

	return (
		String(
			errand?.routeLabel ||
			errand?.route_label ||
			errand?.route ||
			errand?.title ||
			"ErrandBridge",
		)
			.trim() || "ErrandBridge"
	);
}

export function buildRecentLandingReviewPreview({ errand, reviewRating, reviewNotes, user }) {
	const rating = Number(reviewRating);
	if (!Number.isFinite(rating) || rating < 1) return null;

	const quote = truncateLandingReviewQuote(
		reviewNotes ||
		(Number(errand?.id) === -1
			? "Quick to use, clear to follow, and easy to trust from start to finish."
			: "Smooth, reliable updates throughout the errand and everything felt easy to track."),
	);

	return {
		id: `recent-landing-review-${Date.now()}`,
		name: formatLandingReviewName(user),
		region: formatLandingReviewRegion(errand),
		rating: Math.max(1, Math.min(5, Math.round(rating))),
		quote,
	};
}

export function mergeLandingReviewsPreview(recentReview, baseReviews = LANDING_REVIEWS_PREVIEW) {
	const reviews = Array.isArray(baseReviews) ? baseReviews : [];
	if (!recentReview) return reviews;

	return [recentReview, ...reviews.filter((review) => review?.quote !== recentReview.quote)];
}

export function mergePublicLandingReviews(
	recentReview,
	existingReviews = [],
	max = 12,
) {
	const reviews = Array.isArray(existingReviews) ? existingReviews : [];
	if (!recentReview) return reviews;
	const limit = Number.isFinite(Number(max)) ? Math.max(1, Number(max)) : 12;
	return [recentReview, ...reviews.filter((review) => review?.quote !== recentReview.quote)].slice(
		0,
		limit,
	);
}

export function pickMostRecentPendingReviewErrand({ lifecycle, errands }) {
	const pendingIds = new Set(
		Array.isArray(lifecycle?.pendingReviewErrandIds)
			? lifecycle.pendingReviewErrandIds.map((id) => String(id))
			: [],
	);
	if (!pendingIds.size || !Array.isArray(errands)) return null;

	const candidates = errands.filter((errand) => pendingIds.has(String(errand?.id)));
	if (!candidates.length) return null;

	return [...candidates].sort(
		(a, b) =>
			new Date(
				b?.completedAt ||
				b?.completed_at ||
				b?.reviewCompletedAt ||
				b?.createdAt ||
				0,
			).getTime() -
			new Date(
				a?.completedAt ||
				a?.completed_at ||
				a?.reviewCompletedAt ||
				a?.createdAt ||
				0,
			).getTime(),
	)[0];
}

export function shouldShowFloatingReviewIcon({
	lifecycle,
	reviewModalOpen,
	dismissedForSession,
	surface,
	toxiOpen,
}) {
	const allowedSurfaces = new Set(["landing_page", "client_dashboard"]);
	return Boolean(
		lifecycle?.isLoggedIn &&
		lifecycle?.hasPendingReview &&
		Array.isArray(lifecycle?.pendingReviewErrandIds) &&
		lifecycle.pendingReviewErrandIds.length > 0 &&
		!reviewModalOpen &&
		!dismissedForSession &&
		!toxiOpen &&
		allowedSurfaces.has(surface),
	);
}

