const ARCHIVED_REVIEWABLE_STATUS_KEYS = new Set([
	"accepted",
	"delivered",
	"completed",
]);

const COMPLETED_STATUS_KEYS = new Set(["completed", "accepted", "delivered"]);

function normalizeStatusKeyValue(value) {
	if (!value) return null;
	return value
		.toString()
		.trim()
		.toLowerCase()
		.replace(/[^a-z0-9]+/g, "_")
		.replace(/_+/g, "_")
		.replace(/^_+|_+$/g, "");
}

function getHistoryEntryStatusCandidates(entry) {
	if (!entry) return [];
	const candidates = [
		entry.newStatus,
		entry.new_status,
		entry.oldStatus,
		entry.old_status,
	];
	const typeRaw =
		entry.eventType || entry.event_type || entry.type || entry.action || "";
	const type = String(typeRaw).toLowerCase();
	if (type === "admin_assign_pilot" || type.includes("assign")) {
		candidates.push("assigned");
	}
	if (type === "pilot_accept" || type === "pilot_accepted" || type.includes("accept")) {
		candidates.push("accepted");
	}
	if (type === "pilot_started" || type.includes("started")) {
		candidates.push("in_progress");
	}
	if (type.includes("picked_up") || type.includes("pickup")) {
		candidates.push("picked_up");
	}
	if (type.includes("delivered")) {
		candidates.push("delivered");
	}
	if (type === "pilot_completed" || type === "admin_complete" || type.includes("completed")) {
		candidates.push("completed");
	}
	if (type === "admin_cancelled" || type.includes("cancel")) {
		candidates.push("cancelled");
	}
	if (type === "issue_reported" || type.includes("issue")) {
		candidates.push("issue_reported");
	}
	return candidates
		.map((candidate) => normalizeStatusKeyValue(candidate))
		.filter(Boolean);
}

export function deriveErrandStatusKey(errand) {
	if (!errand) return null;
	const history = Array.isArray(errand.history) ? errand.history : [];
	const direct = normalizeStatusKeyValue(errand.status);
	const cancelInHistory = history.some((entry) =>
		getHistoryEntryStatusCandidates(entry).includes("cancelled"),
	);
	if (direct === "cancelled" || cancelInHistory) {
		return "cancelled";
	}

	const best = { key: null, idx: -1 };
	const consider = (candidate) => {
		const key = normalizeStatusKeyValue(candidate);
		if (!key) return;
		const idx = TIMELINE_STATUS_SEQUENCE.indexOf(key);
		if (idx > best.idx) {
			best.key = key;
			best.idx = idx;
		}
	};

	consider(errand.status);
	history.forEach((entry) => {
		getHistoryEntryStatusCandidates(entry).forEach(consider);
	});

	return best.key;
}

export function getEffectiveErrandStatusKey(errand) {
	if (!errand) return null;
	const direct = normalizeStatusKeyValue(errand.status);
	if (direct === "cancelled") return direct;
	const history = Array.isArray(errand.history) ? errand.history : [];
	const hasCancelledHistory = history.some((entry) =>
		getHistoryEntryStatusCandidates(entry).includes("cancelled"),
	);
	if (hasCancelledHistory) return "cancelled";
	if (!history.length) return direct;

	const derived = deriveErrandStatusKey(errand);
	if (!derived) return direct;
	if (!direct) return derived;

	const directIdx = TIMELINE_STATUS_SEQUENCE.indexOf(direct);
	const derivedIdx = TIMELINE_STATUS_SEQUENCE.indexOf(derived);
	if (derivedIdx > directIdx) return derived;
	return direct;
}

export function getHistorySequenceEndStatus({ currentStatus, history = [] }) {
	const normalizedCurrent = normalizeStatusKeyValue(currentStatus);
	if (normalizedCurrent && normalizedCurrent !== "cancelled") {
		return normalizedCurrent;
	}

	const cancelledIndex = TIMELINE_STATUS_SEQUENCE.indexOf("cancelled");
	let bestKey = "submitted";
	let bestIdx = TIMELINE_STATUS_SEQUENCE.indexOf("submitted");

	(history || []).forEach((entry) => {
		if (!entry || entry.synthetic) return;
		getHistoryEntryStatusCandidates(entry).forEach((key) => {
			const idx = TIMELINE_STATUS_SEQUENCE.indexOf(key);
			if (idx >= 0 && idx < cancelledIndex && idx > bestIdx) {
				bestKey = key;
				bestIdx = idx;
			}
		});
	});

	return bestKey;
}

export function countCompletedErrandsForDisplay(errands, backendCount = 0) {
	if (!Array.isArray(errands) || errands.length === 0) {
		return Number(backendCount || 0);
	}

	return errands.filter((errand) => {
		const statusKey = getEffectiveErrandStatusKey(errand);
		return statusKey && COMPLETED_STATUS_KEYS.has(statusKey);
	}).length;
}

function normalizeArchiveUiKey(value) {
	if (!value) return "";
	return String(value).trim().toLowerCase().replace(/\s+/g, "_");
}

export function getArchivedErrandReviewUi({ statusKey, reviewStatusKey, isCustomer }) {
	const normalizedStatusKey = normalizeArchiveUiKey(statusKey);
	const normalizedReviewStatusKey = normalizeArchiveUiKey(reviewStatusKey);
	const isReviewed = normalizedReviewStatusKey === "reviewed";
	const canReview = Boolean(
		isCustomer &&
		ARCHIVED_REVIEWABLE_STATUS_KEYS.has(normalizedStatusKey) &&
		!isReviewed,
	);

	return {
		canReview,
		isReviewed,
		showIndicator: canReview || isReviewed,
		label: canReview ? "⭐ Review now" : isReviewed ? "⭐ Reviewed" : "",
	};
}

function normalizeReviewedRatingValue(value) {
	const rating = Number(value);
	if (!Number.isFinite(rating) || rating <= 0) return null;
	return Math.max(1, Math.min(5, Math.round(rating * 10) / 10));
}

export function buildPendingReviewPromptCopy(errand) {
	const reference = String(
		errand?.title || errand?.referenceNumber || errand?.reference_number || "",
	).trim();
	return {
		headline: "Quick note from Toxi",
		bodyLines: [
			"Hope your errand went well 👋",
			"Please take a moment to rate your Pilot and share feedback.",
		],
		ctaLabel: "Leave a Review ⭐",
		ariaLabel: reference
			? `Leave a review for ${reference}`
			: "Leave a review for your Pilot",
	};
}

export function buildClientReviewSummary(errands) {
	const safeErrands = Array.isArray(errands) ? errands : [];
	const reviewedErrands = safeErrands
		.filter((errand) => {
			const reviewStatusKey = normalizeArchiveUiKey(
				errand?.reviewStatus || errand?.review_status,
			);
			const rating = normalizeReviewedRatingValue(
				errand?.reviewerRating ?? errand?.reviewer_rating,
			);
			return reviewStatusKey === "reviewed" || rating !== null;
		})
		.map((errand) => ({
			id: errand?.id ?? null,
			title: String(
				errand?.title || errand?.referenceNumber || errand?.reference_number || "Errand",
			).trim(),
			referenceNumber: errand?.referenceNumber || errand?.reference_number || null,
			rating: normalizeReviewedRatingValue(
				errand?.reviewerRating ?? errand?.reviewer_rating,
			),
			reviewedAt:
				errand?.reviewCompletedAt ||
				errand?.review_completed_at ||
				errand?.completedAt ||
				errand?.completed_at ||
				errand?.createdAt ||
				errand?.created_at ||
				null,
		}))
		.sort(
			(a, b) =>
				new Date(b?.reviewedAt || 0).getTime() -
				new Date(a?.reviewedAt || 0).getTime(),
		);

	const ratings = reviewedErrands
		.map((errand) => errand.rating)
		.filter((rating) => rating !== null);
	const averageRating = ratings.length
		? Math.round((ratings.reduce((sum, rating) => sum + rating, 0) / ratings.length) * 10) /
		10
		: null;

	return {
		submittedCount: reviewedErrands.length,
		averageRating,
		latestReview: reviewedErrands[0] || null,
	};
}

const ADMIN_ARCHIVED_ERRAND_STATUS_KEYS = new Set(["completed"]);

function normalizeAdminErrandStatusKey(value) {
	return String(value || "").trim().toLowerCase().replace(/\s+/g, "_");
}

function isAdminErrandArchived(errand) {
	return ADMIN_ARCHIVED_ERRAND_STATUS_KEYS.has(
		normalizeAdminErrandStatusKey(errand?.status),
	);
}

function splitAdminErrandsByArchiveState(errands) {
	return (Array.isArray(errands) ? errands : []).reduce(
		(acc, errand) => {
			if (isAdminErrandArchived(errand)) {
				acc.archivedErrands.push(errand);
			} else {
				acc.liveErrands.push(errand);
			}
			return acc;
		},
		{ liveErrands: [], archivedErrands: [] },
	);
}

function mergeAdminArchivedErrands(existingErrands, incomingErrands) {
	const mergedById = new Map();
	[...(Array.isArray(incomingErrands) ? incomingErrands : []), ...(Array.isArray(existingErrands) ? existingErrands : [])]
		.filter(Boolean)
		.forEach((errand) => {
			mergedById.set(String(errand.id), errand);
		});

	return [...mergedById.values()].sort((a, b) => {
		const timeB = new Date(b?.created_at || b?.createdAt || 0).getTime();
		const timeA = new Date(a?.created_at || a?.createdAt || 0).getTime();
		if (timeB !== timeA) return timeB - timeA;
		return Number(b?.id || 0) - Number(a?.id || 0);
	});
}

