// CRA-compatible base for static assets served from /public.
// - In dev this is usually ''
// - In production it can be a sub-path (e.g. '/myapp')
// Keeping it local avoids relying on a global and prevents runtime ReferenceError.
const PUBLIC_ASSET_BASE = process.env.PUBLIC_URL || "";
const resolvePublicAssetUrl = (assetPath) => {
	if (!assetPath) return "";
	const raw = String(assetPath).trim();
	if (!raw) return "";
	if (/^https?:\/\//i.test(raw)) return raw;
	return raw.startsWith("/")
		? `${PUBLIC_ASSET_BASE}${raw}`
		: `${PUBLIC_ASSET_BASE}/${raw}`;
};

