const LANDING_METRIC_TARGETS = {
	verifiedPilots: 120,
	customerSatisfaction: 98.2,
	activeRegions: 4,
	averageCompletionMinutes: 160,
};

function formatLandingMetricValue(metricKey, value) {
	const safeValue = Number.isFinite(Number(value)) ? Number(value) : 0;
	if (metricKey === "verifiedPilots") return `${Math.round(safeValue)}+`;
	if (metricKey === "customerSatisfaction") return `${safeValue.toFixed(1)}%`;
	if (metricKey === "activeRegions") return `${Math.round(safeValue)}`;
	if (metricKey === "averageCompletionMinutes") {
		const totalMinutes = Math.max(0, Math.round(safeValue));
		const hours = Math.floor(totalMinutes / 60);
		const minutes = totalMinutes % 60;
		return `${hours}h ${String(minutes).padStart(2, "0")}m`;
	}
	return String(value);
}

function useAnimatedLandingMetrics(active) {
	const [values, setValues] = useState({
		verifiedPilots: 0,
		customerSatisfaction: 0,
		activeRegions: 0,
		averageCompletionMinutes: 0,
	});
	const hasAnimatedRef = useRef(false);

	useEffect(() => {
		if (!active || hasAnimatedRef.current || typeof window === "undefined") {
			return undefined;
		}
		hasAnimatedRef.current = true;

		if (window.matchMedia?.("(prefers-reduced-motion: reduce)")?.matches) {
			setValues({ ...LANDING_METRIC_TARGETS });
			return undefined;
		}

		const durationMs = 1500;
		const startedAt = window.performance?.now?.() ?? Date.now();
		let frame = 0;

		const update = (timestamp) => {
			const now = Number.isFinite(timestamp)
				? timestamp
				: window.performance?.now?.() ?? Date.now();
			const progress = Math.min(1, (now - startedAt) / durationMs);
			const eased = 1 - (1 - progress) ** 3;

			setValues({
				verifiedPilots: LANDING_METRIC_TARGETS.verifiedPilots * eased,
				customerSatisfaction:
					LANDING_METRIC_TARGETS.customerSatisfaction * eased,
				activeRegions: LANDING_METRIC_TARGETS.activeRegions * eased,
				averageCompletionMinutes:
					LANDING_METRIC_TARGETS.averageCompletionMinutes * eased,
			});

			if (progress < 1) {
				frame = window.requestAnimationFrame(update);
			}
		};

		frame = window.requestAnimationFrame(update);
		return () => {
			if (frame) window.cancelAnimationFrame(frame);
		};
	}, [active]);

	return useMemo(
		() => ({
			verifiedPilots: formatLandingMetricValue(
				"verifiedPilots",
				values.verifiedPilots,
			),
			customerSatisfaction: formatLandingMetricValue(
				"customerSatisfaction",
				values.customerSatisfaction,
			),
			activeRegions: formatLandingMetricValue(
				"activeRegions",
				values.activeRegions,
			),
			averageCompletionMinutes: formatLandingMetricValue(
				"averageCompletionMinutes",
				values.averageCompletionMinutes,
			),
		}),
		[values],
	);
}

