// Canonical, human-readable URL routes for major surfaces.
// - Signed out: /home
// - Signed in: /client
// - Settings modal: /settings
const ROUTE_HOME = "/home";
const ROUTE_CLIENT = "/client";

// Professional auth entrypoints (customer)
// NOTE: We keep signed-in pages under /client/* for now, but the public auth URLs
// should be clean and human-friendly.
const ROUTE_CLIENT_LOGIN = "/login";
const ROUTE_CLIENT_SIGNUP = "/signup";
const ROUTE_SETTINGS = "/settings";

// Expanded URL routes for *all* major in-app pages and overlays.
// These are handled inside App.js (RootRoutes already sends most paths here).
const ROUTE_ADMIN = "/admin";

const ROUTE_HOME_ABOUT = `${ROUTE_HOME}/about`;
const ROUTE_HOME_STORY = `${ROUTE_HOME}/story`;
const ROUTE_HOME_REVIEWS = `${ROUTE_HOME}/reviews`;
const ROUTE_HOME_SUPPORT = `${ROUTE_HOME}/support`;
const ROUTE_HOME_PRICING = `${ROUTE_HOME}/pricing`;

const ROUTE_CLIENT_CREATE = `${ROUTE_CLIENT}/create`;
const ROUTE_CLIENT_ERRANDS = `${ROUTE_CLIENT}/errands`;
const ROUTE_CLIENT_ACTIVITY = `${ROUTE_CLIENT}/activity`;
const ROUTE_CLIENT_DOCUMENTS = `${ROUTE_CLIENT}/documents`;
const ROUTE_CLIENT_PROFILE = `${ROUTE_CLIENT}/profile`;
const ROUTE_CLIENT_PAYMENT = `${ROUTE_CLIENT}/payment`;
const ROUTE_CLIENT_PRICING = `${ROUTE_CLIENT}/pricing`;
const ROUTE_CLIENT_SUPPORT = `${ROUTE_CLIENT}/support`;
const ROUTE_CLIENT_POLICY = `${ROUTE_CLIENT}/policy`;
const ROUTE_CLIENT_SCHEDULE = `${ROUTE_CLIENT}/schedule`;
const ROUTE_CLIENT_PREMIUM_CHECKOUT = `${ROUTE_CLIENT}/premium-checkout`;

const buildClientErrandPath = (errandId, suffix = "") => {
	const id =
		errandId === null || typeof errandId === "undefined" ? "" : String(errandId);
	const safeId = encodeURIComponent(id);
	return `${ROUTE_CLIENT_ERRANDS}/${safeId}${suffix}`;
};

const buildAdminPath = (tab) => {
	const safe = tab ? encodeURIComponent(String(tab)) : "";
	return safe ? `${ROUTE_ADMIN}/${safe}` : ROUTE_ADMIN;
};

const ADMIN_TAB_STORAGE_KEY = "ebAdminTab";

const ADMIN_TABS = new Set([
	"customers",
	"errands",
	"chats",
	"archive",
	"promo-codes",
	"attachments",
	"pilot-applications",
	"issues",
	"stats",
	"incidents",
	"support",
	"availability",
	"calls",
]);

const parseAppRoute = (pathname = "/") => {
	const path = pathname || "/";
	if (path.startsWith("/e/")) return { kind: "share", path };
	if (path.startsWith("/careers")) return { kind: "careers", path };
	if (path.startsWith("/investors")) return { kind: "investors", page: "index", path };
	if (path.startsWith("/tracking/")) {
		const remainder = path.slice("/tracking/".length);
		const parts = remainder.split("/").filter(Boolean);
		const rawId = parts[0] ? decodeURIComponent(parts[0]) : null;
		if (rawId) {
			return {
				kind: "client",
				page: "errand",
				errandId: rawId,
				tracking: true,
				trackingPublic: true,
				path,
			};
		}
	}
	if (path === ROUTE_SETTINGS) return { kind: "settings", path };

	// Root URL should resolve to the canonical public landing.
	if (path === "/") return { kind: "home", page: "home", path };
	if (path === ROUTE_HOME) return { kind: "home", page: "home", path };
	if (path === ROUTE_HOME_ABOUT) return { kind: "home", page: "about", path };
	if (path === ROUTE_HOME_STORY) return { kind: "home", page: "story", path };
	if (path === ROUTE_HOME_REVIEWS) return { kind: "home", page: "reviews", path };
	if (path === ROUTE_HOME_SUPPORT)
		return { kind: "home", page: "support", path };
	if (path === ROUTE_HOME_PRICING)
		return { kind: "home", page: "pricing", path };
	if (path.startsWith(`${ROUTE_HOME}/`))
		return { kind: "home", page: "home", path };

	if (path === ROUTE_ADMIN) {
		let stored = null;
		if (typeof window !== "undefined") {
			try {
				stored = window.localStorage?.getItem(ADMIN_TAB_STORAGE_KEY) || null;
			} catch {
				stored = null;
			}
		}
		const normalized = stored ? String(stored) : "customers";
		return {
			kind: "admin",
			tab: ADMIN_TABS.has(normalized) ? normalized : "customers",
			path,
		};
	}
	if (path.startsWith(`${ROUTE_ADMIN}/`)) {
		const tab = decodeURIComponent(
			path.slice(`${ROUTE_ADMIN}/`.length).split("/")[0] || "customers",
		);
		return {
			kind: "admin",
			tab: ADMIN_TABS.has(tab) ? tab : "customers",
			path,
		};
	}

	if (path === ROUTE_CLIENT) return { kind: "client", page: "base", path };
	if (path === ROUTE_CLIENT_CREATE)
		return { kind: "client", page: "create", path };
	if (path === ROUTE_CLIENT_ERRANDS)
		return { kind: "client", page: "errands", path };
	if (path === ROUTE_CLIENT_ACTIVITY)
		return { kind: "client", page: "activity", path };
	if (path === ROUTE_CLIENT_DOCUMENTS)
		return { kind: "client", page: "documents", path };
	if (path === ROUTE_CLIENT_PROFILE)
		return { kind: "client", page: "profile", path };
	if (path === ROUTE_CLIENT_PAYMENT)
		return { kind: "client", page: "payment", path };
	if (path === ROUTE_CLIENT_PRICING)
		return { kind: "client", page: "pricing", path };
	if (path === ROUTE_CLIENT_SUPPORT)
		return { kind: "client", page: "support", path };
	if (path === ROUTE_CLIENT_POLICY)
		return { kind: "client", page: "policy", path };
	if (path === ROUTE_CLIENT_SCHEDULE)
		return { kind: "client", page: "schedule", path };
	if (path === ROUTE_CLIENT_PREMIUM_CHECKOUT)
		return { kind: "client", page: "premium-checkout", path };

	if (path.startsWith(`${ROUTE_CLIENT_ERRANDS}/`)) {
		const remainder = path.slice(`${ROUTE_CLIENT_ERRANDS}/`.length);
		const parts = remainder.split("/").filter(Boolean);
		const rawId = parts[0] ? decodeURIComponent(parts[0]) : null;
		const sub = parts[1] ? decodeURIComponent(parts[1]) : null;
		if (rawId) {
			if (sub === "tracking")
				return {
					kind: "client",
					page: "errand",
					errandId: rawId,
					tracking: true,
					path,
				};
			if (sub === "edit")
				return { kind: "client", page: "edit", errandId: rawId, path };
			if (sub === "review")
				return { kind: "client", page: "review", errandId: rawId, path };
			return {
				kind: "client",
				page: "errand",
				errandId: rawId,
				tracking: false,
				path,
			};
		}
	}

	if (path.startsWith(`${ROUTE_CLIENT}/`))
		return { kind: "client", page: "base", path };
	return { kind: "unknown", path };
};

// Countries with flag emojis and phone country codes for UI display (fresh build trigger)

// ===== API CONFIGURATION =====
// Determine API base URL based on environment
// IMPORTANT: Check Capacitor FIRST before checking production mode
// Port mapping: 8001 (FastAPI backend - main), 8011 (ML service)
// NOTE: Native shells (Xcode/Android Studio) must stay pinned to port 8001 for local dev.
const isCapacitor = (() => {
	if (typeof window === "undefined") return false;
	if (typeof window.Capacitor !== "undefined") return true;
	try {
		const protocol = String(window.location?.protocol || "").toLowerCase();
		return protocol === "capacitor:" || protocol === "ionic:";
	} catch {
		return false;
	}
})();
const isBuildProduction = process.env.NODE_ENV === "production";
const capacitorPlatform =
	isCapacitor && window.Capacitor?.getPlatform
		? window.Capacitor.getPlatform()
		: isCapacitor
			? window.Capacitor?.platform
			: undefined;
const inferredHost =
	typeof window !== "undefined" ? window.location.hostname : "";
const isLocalHost = ["localhost", "127.0.0.1"].includes(inferredHost);
const defaultAppBase =
	typeof window !== "undefined" && isLocalHost
		? window.location.origin
		: "https://www.errandbridge.com";
const defaultPilotBase =
	typeof window !== "undefined" && isLocalHost
		? `${window.location.origin}/pilot`
		: "https://pilot.errandbridge.com";
const resolvePublicBaseUrl = (raw, fallback) => {
	const value = String(raw || "").trim();
	if (!value) return fallback;

	// Allow relative values like "/" to mean "this origin".
	if (value.startsWith("/")) {
		return typeof window !== "undefined" ? window.location.origin : fallback;
	}

	try {
		const url = new URL(value);
		return url.origin;
	} catch {
		return fallback;
	}
};

const isUnsafeLocalBase = (origin) => {
	try {
		const url = new URL(origin);
		return ["localhost", "127.0.0.1"].includes(url.hostname);
	} catch {
		return false;
	}
};

const joinOriginAndPath = (origin, path) => {
	const base = String(origin || "").replace(/\/+$/, "");
	const p = String(path || "");
	const nextPath = p.startsWith("/") ? p : `/${p}`;
	return `${base}${nextPath}`;
};

const normalizeBaseUrl = (value) => String(value || "").trim().replace(/\/+$/, "");

const buildApiUrlCandidates = (baseUrl, path) => {
	const base = normalizeBaseUrl(baseUrl);
	if (!base) return [];

	const variants = [base];
	if (base.endsWith("/s")) {
		variants.push(base.slice(0, -2));
	} else {
		variants.push(`${base}/s`);
	}

	return Array.from(
		new Set(
			variants
				.map((origin) => normalizeBaseUrl(origin))
				.filter(Boolean)
				.flatMap((origin) => {
					const primaryUrl = joinOriginAndPath(origin, path);
					const fallbackUrl = getCapacitorLoopbackFallbackUrl(
						primaryUrl,
						capacitorPlatform,
					);
					return fallbackUrl && fallbackUrl !== primaryUrl
						? [primaryUrl, fallbackUrl]
						: [primaryUrl];
				}),
		),
	);
};

const configuredAppBase = resolvePublicBaseUrl(
	process.env.REACT_APP_APP_BASE_URL,
	defaultAppBase,
);
// Guard rail: never emit localhost links when the page is not running on localhost.
const safeAppBase =
	!isLocalHost && isUnsafeLocalBase(configuredAppBase)
		? defaultAppBase
		: configuredAppBase;

const APP_BASE_URL = safeAppBase;
const PILOT_BASE_URL = process.env.REACT_APP_PILOT_BASE_URL || defaultPilotBase;

// Pilot canonical auth entrypoints (avoid legacy query params like ?login=true).
const PILOT_LOGIN_URL = joinOriginAndPath(PILOT_BASE_URL, "login");
const PILOT_SIGNUP_URL = joinOriginAndPath(PILOT_BASE_URL, "signup");

// Canonical entry URL for consumer app actions (login/signup). This must be a stable
// public URL so assistants/links never leak localhost in real deployments.
const CLIENT_ENTRY_ORIGIN = APP_BASE_URL;

// Official store listing links (preferred over sending badge clicks to a homepage).
// If unset, we render the badge(s) in a disabled "Coming soon" state.
const PILOT_APP_STORE_URL = process.env.REACT_APP_PILOT_APP_STORE_URL || "";
const PILOT_GOOGLE_PLAY_URL =
	process.env.REACT_APP_PILOT_GOOGLE_PLAY_URL || "";

// Main (consumer) app store listing links.
// Backward compatible: if dedicated values are unset, fall back to the pilot URLs.
const APP_STORE_URL =
	process.env.REACT_APP_APP_STORE_URL || PILOT_APP_STORE_URL || "";
const GOOGLE_PLAY_URL =
	process.env.REACT_APP_GOOGLE_PLAY_URL || PILOT_GOOGLE_PLAY_URL || "";

const API_BASE_URL = resolveApiBaseUrl();

export function shouldShowLandingReviewsButton({
	landingVisible,
	reviewsPanelOpen,
	reviewModalOpen,
	hasBlockingOverlay,
	mobileMenuOpen,
	mobileLoginSheetOpen,
}) {
	return Boolean(
		landingVisible &&
		!reviewsPanelOpen &&
		!reviewModalOpen &&
		!hasBlockingOverlay &&
		!mobileMenuOpen &&
		!mobileLoginSheetOpen,
	);
}

export function getLandingReviewPresentation(isMobileViewport = false) {
	return {
		modalMaxWidth: isMobileViewport ? 560 : 720,
		sectionPadding: isMobileViewport ? 12 : 18,
		sectionGap: isMobileViewport ? 10 : 12,
		cardPadding: isMobileViewport ? 12 : 14,
		cardRadius: isMobileViewport ? 12 : 14,
		cardMaxWidth: isMobileViewport ? "min(100%, 440px)" : "100%",
		headerGap: isMobileViewport ? 6 : 10,
		nameFontSize: isMobileViewport ? 12 : 16,
		regionFontSize: isMobileViewport ? 12 : 13,
		quoteFontSize: isMobileViewport ? 13 : 15,
		quoteLineHeight: isMobileViewport ? 1.45 : 1.55,
		quoteLineClamp: isMobileViewport ? 4 : 6,
		quoteMarginTop: isMobileViewport ? 6 : 8,
	};
}

