// --- Testing helpers (pure) ---
// Prefer recents (that exist in the provided chips), then fill from the base ordering.
export function pickPersonalizedTemplateChips({
	smartChips,
	recentTemplates,
	max = 4,
}) {
	const chips = Array.isArray(smartChips) ? smartChips.filter(Boolean) : [];
	const recents = Array.isArray(recentTemplates)
		? recentTemplates.filter((t) => typeof t === "string" && t.trim())
		: [];
	const MAX = Math.max(0, Number.isFinite(max) ? max : 4);

	const templateToChip = new Map(
		chips.filter((c) => c.template).map((c) => [c.template, c]),
	);
	const out = [];
	const seen = new Set();

	for (const recent of recents) {
		const chip = templateToChip.get(recent);
		if (!chip) continue;
		const key = chip.id || chip.label || chip.template;
		if (seen.has(key)) continue;
		out.push(chip);
		seen.add(key);
		if (out.length >= MAX) return out;
	}

	for (const chip of chips) {
		const key = chip.id || chip.label || chip.template;
		if (seen.has(key)) continue;
		out.push(chip);
		seen.add(key);
		if (out.length >= MAX) break;
	}

	return out;
}

