export function decideSurface({
	user,
	showCareersPage,
	activeSurface,
	assistantOpen,
	intentScore,
	growthContext,
	now = Date.now(),
	appPromoSeen,
	pilotPromoSeen,
	landingScrolledPastHero,
	landingReachedLiveProof,
	floatingVideoMinimized,
	floatingVideoHiddenUntil,
}) {
	if (user || showCareersPage) return null;
	if (activeSurface) return null;
	if (assistantOpen) return null;

	const isMobile = !!growthContext?.isMobile;
	const geoBucket = growthContext?.geoBucket || "unknown";
	const returning = !!growthContext?.isReturning;

	// If user shows strong intent, let the assistant win. (Highest priority.)
	// NOTE: The legacy floating assistant surface is disabled (Toxi concierge replaces it).
	// When intent is high, avoid interrupting with promos/story surfaces.
	if (intentScore >= 70) return null;

	// Mobile users: app promo tends to outperform.
	if (isMobile && !appPromoSeen) return "appPromo";

	// Desktop / diaspora: pilot acquisition tends to be stronger.
	const pilotEligible = !isMobile && (geoBucket === "diaspora" || returning);
	if (pilotEligible && !pilotPromoSeen) return "pilotPromo";

	const canShowStory =
		!!landingScrolledPastHero &&
		!floatingVideoMinimized &&
		!(floatingVideoHiddenUntil && floatingVideoHiddenUntil > now);
	if (canShowStory && intentScore < 25) return "videoStory";

	return null;
}

export function detectOnboardingType({
	userIsAdmin = false,
	showAdminDashboard = false,
	hasAdminDashboardNode = false,
	hasPilotDashboardNode = false,
} = {}) {
	if (userIsAdmin && (showAdminDashboard || hasAdminDashboardNode)) {
		return "admin";
	}
	if (hasPilotDashboardNode) {
		return "pilot";
	}
	return "customer";
}

function getInitials(firstName, lastName, email) {
	const first = (firstName || "").trim()[0] || "";
	const last = (lastName || "").trim()[0] || "";
	if (first || last) return `${first}${last}`.toUpperCase();
	return (email || "?").trim()[0]?.toUpperCase() || "?";
}

function getAvatarColor(seed) {
	if (!seed) return AVATAR_COLORS[0];
	let hash = 0;
	for (let i = 0; i < seed.length; i += 1) {
		hash = seed.charCodeAt(i) + ((hash << 5) - hash);
	}
	return AVATAR_COLORS[Math.abs(hash) % AVATAR_COLORS.length];
}
const inferToastType = (message) => {
	if (!message || typeof message !== "string") return "info";
	const normalized = message.toLowerCase();
	if (
		normalized.includes("error") ||
		normalized.includes("failed") ||
		normalized.includes("fail") ||
		normalized.includes("unable")
	) {
		return "error";
	}
	if (
		normalized.includes("warning") ||
		normalized.includes("missing") ||
		normalized.includes("required")
	) {
		return "warning";
	}
	if (
		normalized.includes("success") ||
		normalized.includes("completed") ||
		normalized.includes("approved") ||
		normalized.includes("saved") ||
		normalized.includes("sent") ||
		normalized.includes("updated")
	) {
		return "success";
	}
	return "info";
};

const subscribeToast = (handler) => {
	if (
		typeof window !== "undefined" &&
		typeof window.subscribeToast === "function"
	) {
		return window.subscribeToast(handler);
	}
	if (typeof window !== "undefined" && window?.addEventListener) {
		// Standard in-app notification channel.
		// Any code can dispatch: window.dispatchEvent(new CustomEvent('eb:toast', { detail }))
		window.addEventListener("eb:toast", handler);
		return () => window.removeEventListener("eb:toast", handler);
	}
	return () => { };
};

function getRandomPuzzleIdx(length, excludeIdx = null) {
	if (!length || length <= 1) return 0;
	let idx;
	do {
		idx = Math.floor(Math.random() * length);
	} while (excludeIdx !== null && idx === excludeIdx);
	return idx;
}

const ClientNotificationBanner = memo(function ClientNotificationBanner({
	notification,
	onActivate,
	onDismiss,
}) {
	if (!notification) return null;

	const background =
		notification.type === "approved" ? "#059669" : "#3b82f6";
	const icon = notification.type === "approved" ? "✅" : "ℹ️";

	return (
		<button
			type="button"
			className="notification"
			style={{
				position: "fixed",
				top: 0,
				left: 0,
				right: 0,
				background,
				color: "#fff",
				padding: "calc(12px + env(safe-area-inset-top, 0px)) 24px 12px",
				textAlign: "center",
				fontWeight: 600,
				fontSize: 16,
				zIndex: 1000,
				cursor: "pointer",
				boxShadow: "0 4px 12px rgba(0, 0, 0, 0.15)",
				display: "flex",
				alignItems: "center",
				justifyContent: "center",
				gap: 12,
				border: "none",
				width: "100%",
			}}
			onClick={() => {
				onActivate?.(notification);
				onDismiss?.();
			}}
			onKeyDown={(event) => {
				if (event.key === "Enter" || event.key === " ") {
					event.preventDefault();
					onActivate?.(notification);
					onDismiss?.();
				}
			}}
		>
			<span style={{ fontSize: 20 }}>{icon}</span>
			<span>{notification.message}</span>
		</button>
	);
});

