		try {
			const state = landingScrollLockRef?.current;
			if (state) {
				state.count = 0;
				state.restoreOverflow = "";
				state.restorePaddingRight = "";
			}
		} catch {
			// ignore
		}

		// Clear any surface registry so nothing remains "blocking".
		try {
			closeAllSurfaces?.();
			closeModalSurface?.();
			closePanel?.();
		} catch {
			// ignore
		}

