	async function handleAssignPilotToErrand(errandId, pilotId) {
		if (!pilotId) {
			showActionToast("Select a pilot first.", { type: "warning" });
			return;
		}
		try {
			const token = localStorage.getItem("authToken") || cache.getAuthToken();
			if (!token) {
				alert("❌ Not authenticated");
				return;
			}

			const response = await fetch(
				`${API_BASE_URL}/admin/errands/${errandId}/assign-pilot`,
				{
					method: "POST",
					headers: {
						"Content-Type": "application/json",
						Authorization: `Bearer ${token}`,
					},
					body: JSON.stringify({ pilot_id: Number(pilotId) }),
				},
			);

			const data = await response.json().catch(() => ({}));
			if (!response.ok) {
				alert(`❌ Error assigning pilot: ${data.detail || "Unknown error"}`);
				return;
			}

			setAdminErrandsList((prev) =>
				prev.map((errand) =>
					errand.id === errandId
						? {
							...errand,
							pilot_id: Number(pilotId),
							status: data.status || errand.status,
							assigned_at: data.assignedAt || errand.assigned_at,
						}
						: errand,
				),
			);
			showActionToast("✅ Pilot assigned successfully!", { type: "success" });
		} catch (err) {
			console.error("Error assigning pilot:", err);
			alert("❌ Failed to assign pilot. Please try again.");
			loadAdminData();
		}
	}

	async function handleUpdatePilotDispatchStatus(pilotId, action, note = "") {
		if (!pilotId || !action) return;
		try {
			const token = localStorage.getItem("authToken") || cache.getAuthToken();
			if (!token) {
				showActionToast("Admin session missing. Please log in again.", {
					type: "warning",
				});
				return;
			}

			const response = await fetch(
				`${API_BASE_URL}/admin/pilots/${pilotId}/dispatch-status`,
				{
					method: "POST",
					headers: {
						"Content-Type": "application/json",
						Authorization: `Bearer ${token}`,
					},
					body: JSON.stringify({ action, note }),
				},
			);

			const data = await response.json().catch(() => ({}));
			if (!response.ok) {
				showActionToast(data.detail || "Unable to update pilot dispatch access.", {
					type: "warning",
				});
				return;
			}

			setAdminCustomers((prev) =>
				(Array.isArray(prev) ? prev : []).map((customer) =>
					Number(customer?.id) === Number(pilotId)
						? {
							...customer,
							availability: data.availability,
							admin_dispatch_status: data.admin_dispatch_status,
							can_accept_jobs: data.can_accept_jobs,
							dispatch_block_reason: data.dispatch_block_reason,
							admin_dispatch_note: data.admin_dispatch_note,
						}
						: customer,
				),
			);
			showActionToast("Pilot dispatch access updated.", { type: "success" });
		} catch (error) {
			console.error("Error updating pilot dispatch access:", error);
			showActionToast("Unable to update pilot dispatch access.", {
				type: "warning",
			});
		}
	}

	async function handleUpdatePilotDispatchPolicy(updates = {}) {
		try {
			const token = localStorage.getItem("authToken") || cache.getAuthToken();
			if (!token) {
				showActionToast("Admin session missing. Please log in again.", {
					type: "warning",
				});
				return;
			}

			const response = await fetch(
				`${API_BASE_URL}/admin/pilot-dispatch-policy`,
				{
					method: "PUT",
					headers: {
						"Content-Type": "application/json",
						Authorization: `Bearer ${token}`,
					},
					body: JSON.stringify(updates),
				},
			);

			const data = await response.json().catch(() => ({}));
			if (!response.ok) {
				showActionToast(data.detail || "Unable to update pilot dispatch policy.", {
					type: "warning",
				});
				return;
			}

			setAdminPilotDispatchPolicy(data);
			showActionToast("Pilot dispatch policy updated.", { type: "success" });
		} catch (error) {
			console.error("Error updating pilot dispatch policy:", error);
			showActionToast("Unable to update pilot dispatch policy.", {
				type: "warning",
			});
		}
	}
