	// Single source of truth for opening auth UI.
	// Rationale: navigating to the same URL (e.g. /client?login=true) doesn't always
	// re-trigger effects, so we also explicitly open the modal.
	const openClientAuth = useCallback(
		(mode = "login", options = {}) => {
			const nextMode = mode === "signup" ? "signup" : "login";
			const nextPath =
				nextMode === "signup" ? ROUTE_CLIENT_SIGNUP : ROUTE_CLIENT_LOGIN;
			const ref = options?.ref ? String(options.ref).trim() : "";
			const returnToRaw = options?.returnTo ? String(options.returnTo).trim() : "";
			const returnTo = returnToRaw.startsWith("/") ? returnToRaw : "";
			const nextUrl = `${nextPath}${ref ? `?ref=${encodeURIComponent(ref)}` : ""}`;

			if (typeof window !== "undefined") {
				try {
					if (returnTo) {
						window.sessionStorage?.setItem(POST_AUTH_RETURN_TO_KEY, returnTo);
					} else {
						window.sessionStorage?.removeItem(POST_AUTH_RETURN_TO_KEY);
					}
				} catch {
					// ignore
				}
			}

			// Close any role chooser surfaces so the AuthModal is visible.
			setMobileLoginSheetOpen(false);
			setLoginDropdownOpen(false);
			setMobileMenuOpen(false);

			setAuthMode(nextMode);
			setAuthModalOpen(true);
			setAuthModalFromQuery(false);
			openModalSurface("loginSheet");

			// Keep URL meaningful for refresh/share/back.
			try {
				if (publicPath !== nextPath || search !== (ref ? `?ref=${encodeURIComponent(ref)}` : "")) {
					navigate(nextUrl);
				}
			} catch {
				// ignore
			}
		},
		[navigate, openModalSurface, publicPath, search],
	);

	const clearAuthQueryParams = useCallback(() => {
		if (typeof window === "undefined") return;
		const url = new URL(window.location.href);
		const isClientAuthPath =
			url.pathname === ROUTE_CLIENT_LOGIN || url.pathname === ROUTE_CLIENT_SIGNUP;
		const hasLegacyMarkers =
			url.searchParams.has("login") || url.searchParams.has("signup");
		if (!hasLegacyMarkers && !isClientAuthPath) return;

		url.searchParams.delete("login");
		url.searchParams.delete("signup");
		// If the user is on a dedicated auth route, return to the public landing.
		if (isClientAuthPath) {
			url.pathname = "/";
		}
		const newSearch = url.searchParams.toString();
		const newUrl = `${url.pathname}${newSearch ? `?${newSearch}` : ""}${url.hash}`;
		window.history.replaceState({}, "", newUrl);
	}, []);
	const handleAuthBack = useCallback(() => {
		if (typeof window !== "undefined") {
			try {
				window.sessionStorage?.removeItem(POST_AUTH_RETURN_TO_KEY);
			} catch {
				// ignore
			}
		}
		clearAuthQueryParams();
		setAuthModalOpen(false);
		setAuthModalFromQuery(false);
	}, [clearAuthQueryParams]);
	useEffect(() => {
		if (typeof window === "undefined") return;
		const url = new URL(window.location.href);
		const params = url.searchParams;
		const path = url.pathname || "";
		const isClientLoginPath = path === ROUTE_CLIENT_LOGIN;
		const isClientSignupPath = path === ROUTE_CLIENT_SIGNUP;
		if (isClientLoginPath) {
			// Ensure other surfaces don't cover the AuthModal.
			setMobileLoginSheetOpen(false);
			setLoginDropdownOpen(false);
			setMobileMenuOpen(false);
			setAuthMode("login");
			setAuthModalOpen(true);
			setAuthModalFromQuery(true);
			openModalSurface("loginSheet");
			return;
		}
		if (isClientSignupPath) {
			setMobileLoginSheetOpen(false);
			setLoginDropdownOpen(false);
			setMobileMenuOpen(false);
			setAuthMode("signup");
			setAuthModalOpen(true);
			setAuthModalFromQuery(true);
			openModalSurface("loginSheet");
			return;
		}
		if (params.get("login") === "true") {
			// Ensure other surfaces don't cover the AuthModal.
			setMobileLoginSheetOpen(false);
			setLoginDropdownOpen(false);
			setMobileMenuOpen(false);
			setAuthMode("login");
			setAuthModalOpen(true);
			setAuthModalFromQuery(true);
			openModalSurface("loginSheet");
		}
		if (params.get("signup") === "true") {
			setMobileLoginSheetOpen(false);
			setLoginDropdownOpen(false);
			setMobileMenuOpen(false);
			setAuthMode("signup");
			setAuthModalOpen(true);
			setAuthModalFromQuery(true);
			openModalSurface("loginSheet");
		}
	}, [openModalSurface]);

	useEffect(() => {
		if (user) return;
		// IMPORTANT: do not auto-open auth UI on the landing (/client) or settings.
		// Auth UI should appear only after user intent (click) or explicit URL intent.
		const params = new URLSearchParams(search);
		const legacyLogin = params.get("login") === "true";
		const legacySignup = params.get("signup") === "true";
		const isExplicitAuthPath =
			publicPath === ROUTE_CLIENT_LOGIN || publicPath === ROUTE_CLIENT_SIGNUP;

		if (!isExplicitAuthPath && !legacyLogin && !legacySignup) return;

		const nextMode =
			publicPath === ROUTE_CLIENT_SIGNUP || legacySignup ? "signup" : "login";
		setAuthMode(nextMode);
		setAuthModalFromQuery(true);

		// Close any "Continue as" surfaces so the login form is visible.
		setMobileLoginSheetOpen(false);
		setLoginDropdownOpen(false);
		setMobileMenuOpen(false);
		setAuthModalOpen(true);
		openModalSurface("loginSheet");
	}, [openModalSurface, publicPath, search, user]);

	useEffect(() => {
		if (authModalOpen || mobileLoginSheetOpen) {
			openModalSurface("loginSheet");
		} else {
			closeModalSurface();
		}
	}, [
		authModalOpen,
		mobileLoginSheetOpen,
		openModalSurface,
		closeModalSurface,
	]);

	useEffect(() => {
		if (!loginDropdownOpen) return undefined;

		const handleKeyDown = (event) => {
			if (event.key === "Escape") {
				setLoginDropdownOpen(false);
			}
		};

		const handleMouseDown = (event) => {
			const target = event.target;
			if (!(target instanceof Node)) return;
			if (!loginDropdownRef.current) return;
			if (!loginDropdownRef.current.contains(target)) {
				setLoginDropdownOpen(false);
			}
		};

		window.addEventListener("keydown", handleKeyDown);
		window.addEventListener("mousedown", handleMouseDown);

		return () => {
			window.removeEventListener("keydown", handleKeyDown);
			window.removeEventListener("mousedown", handleMouseDown);
		};
	}, [loginDropdownOpen]);

	useEffect(() => {
		if (!mobileLoginSheetOpen) return undefined;

		setLoginDropdownOpen(false);

		const handleKeyDown = (event) => {
			if (event.key === "Escape") {
				setMobileLoginSheetOpen(false);
			}
		};

		window.addEventListener("keydown", handleKeyDown);
		return () => window.removeEventListener("keydown", handleKeyDown);
	}, [mobileLoginSheetOpen]);

	const googleClientId = process.env.REACT_APP_GOOGLE_CLIENT_ID || "";
	const googleAuthEnabledFlag = (
		process.env.REACT_APP_GOOGLE_AUTH_ENABLED || ""
	).toLowerCase();
	const googleAuthAllowedHosts = (process.env.REACT_APP_GOOGLE_AUTH_HOSTS || "")
		.split(",")
		.map((host) => host.trim())
		.filter(Boolean);
	const currentHost =
		typeof window !== "undefined" ? window.location.hostname : "";
	const isLocalHost = currentHost === "localhost" || currentHost === "127.0.0.1";
	const isPrivateNetworkHost = /^10\.|^192\.168\.|^172\.(1[6-9]|2\d|3[0-1])\./.test(
		currentHost || "",
	);
	const isLocalDevHost =
		isLocalHost ||
		(process.env.NODE_ENV !== "production" &&
			(isPrivateNetworkHost || String(currentHost || "").endsWith(".local")));
	const googleAuthHostAllowed =
		isLocalDevHost ||
		googleAuthAllowedHosts.length === 0 ||
		googleAuthAllowedHosts.some((host) => {
			if (!host) return false;
			if (currentHost === host) return true;
			return currentHost.endsWith(`.${host}`);
		});
	const googleIdentityAuthRequested =
		Boolean(googleClientId) &&
		googleAuthEnabledFlag !== "false" &&
		googleAuthHostAllowed;
	const googleAuthDisabledReason = !googleClientId
		? "Google sign-in isn’t configured yet."
		: !googleAuthHostAllowed
			? `Google sign-in is disabled for ${currentHost || "this domain"}.`
			: googleAuthEnabledFlag === "false"
				? "Google sign-in is disabled."
				: "Google sign-in isn’t available right now.";
	const googleButtonRef = useRef(null);
