				templateId: findTemplateByName(String(template || "").trim())?.id || null,
				categoryId: pricingCategoryKey,
				laneKey: pricingLaneKey,
				supportType,
				startLocation: pickup,
				endLocation: dropoff,
				priority: pricingTierKey,
				schedule,
				currency: paymentCurrency,
