	const pickupWindowSummary = useMemo(() => {
		const dateValue = pickupTimeSlotDate;
		const startValue = pickupTimeSlotStart;
		const endValue = pickupTimeSlotEnd;

		if (!dateValue) {
			return startValue || endValue ? "Pickup time set (date missing)" : "Not set";
		}

		if (!isValidDateInputValue(dateValue)) {
			return "Not set";
		}

		const parseLocalDate = (value) => {
			const parts = String(value).split("-").map((p) => Number(p));
			if (parts.length !== 3) return null;
			const [year, month, day] = parts;
			if (!year || !month || !day) return null;
			return new Date(year, month - 1, day);
		};

		const formatDayLabel = (value) => {
			if (value === todayDate) return "Today";
			try {
				const todayLocal = parseLocalDate(todayDate);
				const targetLocal = parseLocalDate(value);
				if (todayLocal && targetLocal) {
					const tomorrowLocal = new Date(todayLocal);
					tomorrowLocal.setDate(tomorrowLocal.getDate() + 1);
					const isTomorrow =
						targetLocal.getFullYear() === tomorrowLocal.getFullYear() &&
						targetLocal.getMonth() === tomorrowLocal.getMonth() &&
						targetLocal.getDate() === tomorrowLocal.getDate();
					if (isTomorrow) return "Tomorrow";
				}
			} catch {
				// ignore
			}

			const dateObj = parseLocalDate(value);
			if (!dateObj) return value;
			const now = new Date();
			const includeYear = dateObj.getFullYear() !== now.getFullYear();
			return new Intl.DateTimeFormat(locale || undefined, {
				weekday: "short",
				month: "short",
				day: "numeric",
				...(includeYear ? { year: "numeric" } : {}),
			}).format(dateObj);
		};

		const formatTimeLabel = (value) => {
			if (!isValidTimeInputValue(value)) return "";
			const base = parseLocalDate(dateValue) || new Date();
			const [hours, minutes] = String(value)
				.split(":")
				.map((p) => Number(p));
			base.setHours(hours || 0, minutes || 0, 0, 0);
			return new Intl.DateTimeFormat(locale || undefined, {
				hour: "numeric",
				minute: "2-digit",
			}).format(base);
		};

		const dayLabel = formatDayLabel(dateValue);
		const startLabel = startValue ? formatTimeLabel(startValue) : "";
		const endLabel = endValue ? formatTimeLabel(endValue) : "";

		if (startLabel && endLabel) return `${dayLabel} • ${startLabel}–${endLabel}`;
		if (startLabel) return `${dayLabel} • ${startLabel}`;
		if (endLabel) return `${dayLabel} • by ${endLabel}`;
		return dayLabel;
	}, [locale, pickupTimeSlotDate, pickupTimeSlotEnd, pickupTimeSlotStart, todayDate]);
	const attachmentsSummary = effectiveSelectedFiles.length
