	const resolveSensitivityForTemplate = useCallback(
		(templateName) => {
			// Prefer catalog metadata when available so v2 templates map cleanly
			// to the existing sensitivity tiers (documents/sensitive/property/etc.).
			const catalogMatch = findTemplateByName(templateName);
			const laneKey = String(catalogMatch?.laneKey || "").trim();
			if (laneKey && laneKey !== "routine") {
				return resolveV2LaneSensitivity(laneKey);
			}

			const name = (templateName || "").toLowerCase();
			if (name.includes("inspection") || name.includes("verification")) {
				return "Bulk/Heavy";
			}
			if (
				name.includes("official") ||
				name.includes("government") ||
				name.includes("legal") ||
				name.includes("immigration")
			) {
				return "Confidential (legal, personal, etc.)";
			}
			if (name.includes("medical") || name.includes("pharmacy")) {
				return "Sensitive (documents, money, medicine)";
			}
			if (name.includes("electronics") || name.includes("repair")) {
				return "Fragile (electronics, glass, etc.)";
			}
			if (
				name.includes("grocery") ||
				name.includes("food") ||
				name.includes("market") ||
				name.includes("laundry")
			) {
				return "Perishable (food, flowers, etc.)";
			}
			return "Normal";
		},
		[findTemplateByName, resolveV2LaneSensitivity],
	);

	const toggleAttachmentsEnabled = useCallback(
		(enabled) => {
			setAttachmentsEnabled(enabled);
			if (!enabled) {
				clearSelectedFiles();
			}
		},
		[clearSelectedFiles],
	);

	const handleClearTemplate = useCallback(() => {
		latestTemplateRef.current = "";
		templateAutoMatchDisabledRef.current = true;
		setTemplate("");
		setNote("");
		lastTemplateAutofillNoteRef.current = "";
		setTemplateJustChanged(false);
		setSensitivity("Normal");
	}, []);

	useEffect(() => {
		if (!template) return;
		setSensitivity(resolveSensitivityForTemplate(template));
	}, [resolveSensitivityForTemplate, template]);

	const handleUseSuggestion = useCallback(() => {
		latestTemplateRef.current = template;
		templateAutoMatchDisabledRef.current = false;
		const cachedSuggestion = getTemplateSuggestionSync(template);
		const applySuggestion = (suggestion) => {
			const nextSuggestion =
				(suggestion || "").trim() || buildFallbackTemplateNote(template);
			if (!nextSuggestion) return;

			// If the user hasn't set an Errand Topic yet, seed it with the current template.
			setTitle((prev) =>
				prev?.trim() ? prev : formatTemplateTitle(template || ""),
			);
			setNote(nextSuggestion);
			lastTemplateAutofillNoteRef.current = nextSuggestion;
			setSensitivity(resolveSensitivityForTemplate(template));
		};

		if (cachedSuggestion) {
			applySuggestion(cachedSuggestion);
			return;
		}

		loadTemplateData().then((data) => {
			if (latestTemplateRef.current !== template) return;
			applySuggestion(data.TEMPLATE_SUGGESTIONS?.[template] || "");
		});
	}, [
		buildFallbackTemplateNote,
		getTemplateSuggestionSync,
		loadTemplateData,
		resolveSensitivityForTemplate,
		template,
	]);

	const handleFeatureTemplateSelect = useCallback(
		(templateName, options = {}) => {
			if (!templateName) return;
			const previousTemplate = template;
			latestTemplateRef.current = templateName;
			templateAutoMatchDisabledRef.current = false;
			setTemplate(templateName);
			// Track this template as "recent" for the suggested-chip row.
			try {
				if (typeof window !== "undefined") {
					const identity = user?.id || user?.email || "guest";
					const storageKey = `eb:recent-templates:${identity}`;
					const raw = localStorage.getItem(storageKey);
					const parsed = raw ? JSON.parse(raw) : [];
					const current = Array.isArray(parsed)
						? parsed.filter((t) => typeof t === "string" && t.trim().length > 0)
						: [];
					const next = [
						String(templateName).trim(),
						...current.filter((x) => x !== templateName),
					].slice(0, 8);
					localStorage.setItem(storageKey, JSON.stringify(next));
				}
			} catch {
				// ignore
			}
			const autofill = options.autofill !== false;
			const forceAutofill = Boolean(options.forceAutofill);
			if (autofill) {
				const cachedSuggestion = getTemplateSuggestionSync(templateName);
				if (cachedSuggestion) {
					setNote((prev) => {
						if (
							!forceAutofill &&
							!shouldOverwriteNoteWithTemplate(prev, previousTemplate)
						)
							return prev;
						lastTemplateAutofillNoteRef.current = cachedSuggestion;
						return cachedSuggestion;
					});
				} else {
					loadTemplateData().then((data) => {
						if (latestTemplateRef.current !== templateName) return;
						const suggested = (
							data.TEMPLATE_SUGGESTIONS?.[templateName] || ""
						).trim();
						const nextNote =
							suggested || buildFallbackTemplateNote(templateName);
						if (!nextNote) return;
						setNote((prev) => {
							if (
								!forceAutofill &&
								!shouldOverwriteNoteWithTemplate(prev, previousTemplate)
							)
								return prev;
							lastTemplateAutofillNoteRef.current = nextNote;
							return nextNote;
						});
					});
				}
			}
			setTemplateJustChanged(true);
			setTimeout(() => setTemplateJustChanged(false), 2000);
		},
		[
			buildFallbackTemplateNote,
			getTemplateSuggestionSync,
			loadTemplateData,
			shouldOverwriteNoteWithTemplate,
			template,
			user?.email,
			user?.id,
		],
	);

	const handleV2TemplateSelect = useCallback(
		(rawTemplate) => {
			const nameFromArg =
				typeof rawTemplate === "string"
					? rawTemplate
					: rawTemplate?.name;
			const pickedName = String(nameFromArg || "").trim();
			if (!pickedName) return;

			const catalogMatch = findTemplateByName(pickedName);
			const laneKey =
				String(
					(catalogMatch?.laneKey || rawTemplate?.laneKey || pricingLaneKey || "") ??
					"",
				).trim();

			if (laneKey) {
				setPricingLaneKey(laneKey);
				setPricingTierKey((prev) => String(prev || "standard"));
				setSensitivity(resolveV2LaneSensitivity(laneKey));
			}

			setTitle((prev) => {
				if (String(prev || "").trim()) return prev;
				return pickedName.slice(0, 80);
			});

			const noteTrim = String(note || "").trim();
			const laneDefault = laneKey ? String(resolveV2LaneDefaultNote(laneKey) || "").trim() : "";
			const shouldForceAutofill = !noteTrim || (laneDefault && noteTrim === laneDefault);
			handleFeatureTemplateSelect(pickedName, {
				autofill: true,
				forceAutofill: shouldForceAutofill,
			});
		},
		[
			findTemplateByName,
			handleFeatureTemplateSelect,
			note,
			pricingLaneKey,
			resolveV2LaneDefaultNote,
			resolveV2LaneSensitivity,
		],
	);

	const focusErrandTopic = useCallback(() => {
		const el = titleInputRef.current;
		if (!el) return;
		try {
			el.scrollIntoView({ behavior: "smooth", block: "center" });
		} catch {
			// Older browsers can throw if scrollIntoView options aren't supported.
			el.scrollIntoView();
		}
		// Defer focus slightly so scroll/paint happens first, especially on mobile.
		window.setTimeout(() => {
			try {
				el.focus({ preventScroll: true });
			} catch {
				el.focus();
			}
			// Put the caret at the end.
			try {
				const len = el.value?.length ?? 0;
				el.setSelectionRange(len, len);
			} catch {
				// ignore
			}
		}, 50);
	}, []);

	const handleFeatureSuggestionClick = useCallback(
		(item, options = {}) => {
			if (!item) return;
			// Keep existing behavior: selecting a chip picks a template + suggested description.
			if (item.template) {
				handleFeatureTemplateSelect(item.template, {
					autofill: true,
					forceAutofill: Boolean(options?.forceAutofill),
				});
			}
			// Legacy flow: fill Errand Topic and focus it.
			// Premium flow removes the title input; avoid extra state updates that can
			// make taps feel “laggy” on iOS.
			if (titleInputRef.current) {
				const nextTopic =
					typeof item.label === "string" ? item.label.trim() : "";
				if (nextTopic) {
					setTitle(nextTopic);
				}
				focusErrandTopic();
			}
		},
		[focusErrandTopic, handleFeatureTemplateSelect],
	);

	const buildSmartTemplateSuggestions = useCallback((rawText) => {
		const text = (rawText || "").toLowerCase();
		const base = [
			{
				id: "courier_document_delivery",
				label: "Document delivery",
				template: "Courier / Document Delivery",
				icon: "📄",
				description: "Deliver documents with signature confirmation.",
				starter: FINAL_DEMO_PRESET.note,
				keywords: [
					"document",
					"documents",
					"courier",
					"delivery",
					"pickup",
					"dropoff",
					"signature",
					"deliver",
					"dispatch",
					"dhl",
					"fedex",
					"passport",
					"vfs",
				],
			},
			{
				id: "missrey_shopper",
				label: "Mystery Shopper",
				template: "Mystery Shopper",
				icon: "🛍️",
				description: "Shop from stores/markets and deliver items.",
				starter:
					"Shop these items and deliver to my address. Follow substitution preferences and keep receipts if available.",
				keywords: [
					"mystery",
					"mystery shopper",
					"shopper",
					"shopping",
					"store",
					"market",
					"boutique",
					"buy",
					"purchase",
					"order",
					"errand",
				],
			},
			{
				id: "grocery_run",
				label: "Grocery Run",
				template: "Grocery / Market Run",
				icon: "🛒",
				description: "Shop and deliver essentials quickly.",
				starter:
					"Shop at a nearby supermarket and deliver to my address. Follow substitution preferences.",
				keywords: [
					"grocery",
					"groceries",
					"market",
					"supermarket",
					"shopping",
					"shop",
					"buy",
					"produce",
					"food",
				],
			},
			{
				id: "airport_pickup",
				label: "Airport pickup",
				template: "Travel / Airport Assistance",
				icon: "✈️",
				description: "Driver pickup for arrivals.",
				starter:
					"Pick up John at MMA2 arrivals. Flight: BA75. ETA: 6:40pm. Ending location: VI Lagos.",
				keywords: [
					"airport",
					"flight",
					"arrival",
					"arrivals",
					"terminal",
					"mma",
					"mma2",
					"muritala",
					"murtala",
					"heathrow",
					"gatwick",
					"boarding",
				],
			},
		];

		const tokenize = (value) =>
			String(value || "")
				.toLowerCase()
				.split(/\s+/)
				.filter(Boolean);
		const tokens = tokenize(text);
		const scoreFor = (item) => {
			if (!tokens.length) return 0;
			let score = 0;
			for (const token of tokens) {
				if (item.keywords?.some((k) => k.includes(token) || token.includes(k)))
					score += 3;
			}
			if (
				item.template &&
				(text.includes(item.template.toLowerCase()) ||
					text.includes(item.label.toLowerCase()))
			)
				score += 4;
			return score;
		};

		const scored = base
			.map((item) => ({ ...item, score: scoreFor(item) }))
			.sort((a, b) => b.score - a.score || a.label.localeCompare(b.label));

		// Always show a small, stable set. If nothing matches, show the familiar ordering.
		const anyMatch = scored.some((s) => s.score > 0);
		if (!anyMatch) return base;
		return scored.slice(0, 5);
	}, []);

	const smartTemplateSuggestions = useMemo(
		() => buildSmartTemplateSuggestions(note),
		[buildSmartTemplateSuggestions, note],
	);
	const step1HelperCopy = useMemo(
		() => STEP1_TEMPLATE_HELPER_COPY[template] || DEFAULT_STEP1_HELPER_COPY,
		[template],
	);

	// Recently used templates (personalize the 4-chip suggested row).
	// Stored per-user when possible; falls back to guest.
	const recentTemplatesStorageKey = useMemo(() => {
		const identity = user?.id || user?.email || "guest";
		return `eb:recent-templates:${identity}`;
	}, [user?.email, user?.id]);

	const readRecentTemplates = useCallback(() => {
		if (typeof window === "undefined") return [];
		try {
			const raw = localStorage.getItem(recentTemplatesStorageKey);
			if (!raw) return [];
			const parsed = JSON.parse(raw);
			if (!Array.isArray(parsed)) return [];
			return parsed.filter((t) => typeof t === "string" && t.trim().length > 0);
		} catch {
			return [];
		}
	}, [recentTemplatesStorageKey]);

	const personalizedTemplateChips = useMemo(() => {
		const MAX = 4;

		const templateToChip = new Map(
			(smartTemplateSuggestions || [])
				.filter(Boolean)
				.filter((c) => c.template)
				.map((c) => [c.template, c]),
		);

		const out = [];
		const seen = new Set();

		// 1) Recents first (if they exist in the current chip set).
		for (const recent of readRecentTemplates()) {
			const chip = templateToChip.get(recent);
			if (!chip) continue;
			const key = chip.id || chip.label || chip.template;
			if (seen.has(key)) continue;
			out.push(chip);
			seen.add(key);
			if (out.length >= MAX) return out;
		}

		// 2) Fill remaining from smart ordering.
		for (const chip of smartTemplateSuggestions || []) {
			if (!chip) continue;
			const key = chip.id || chip.label || chip.template;
			if (seen.has(key)) continue;
			out.push(chip);
			seen.add(key);
			if (out.length >= MAX) break;
		}

		return out;
	}, [readRecentTemplates, smartTemplateSuggestions]);

	useEffect(() => {
		if (!finalDemoMode) return;
		if (finalDemoAppliedRef.current) return;
		finalDemoAppliedRef.current = true;

		// Apply the preset once per session so screenshots stay consistent.
		latestTemplateRef.current = FINAL_DEMO_PRESET.template;
		setTemplate(FINAL_DEMO_PRESET.template);
		setNote(FINAL_DEMO_PRESET.note);
		setPickup(FINAL_DEMO_PRESET.pickup);
		setDropoff(FINAL_DEMO_PRESET.dropoff);
		setScheduleType("now");
	}, [finalDemoMode]);

	const [templateBrowserOpen, setTemplateBrowserOpen] = useState(false);
	const [templateBrowserQuery, setTemplateBrowserQuery] = useState("");

	const templateCatalog = useMemo(() => TEMPLATE_CATALOG, []);

	const filteredTemplateLibrary = useMemo(() => {
		const q = templateBrowserQuery.trim().toLowerCase();
		if (!q) return templateCatalog;
		return templateCatalog.filter(
			(t) =>
				t.name.toLowerCase().includes(q) ||
				(t.description || "").toLowerCase().includes(q) ||
				(t.category || "").toLowerCase().includes(q),
		);
	}, [templateBrowserQuery, templateCatalog]);

	// Draft status for Step 1 note (debounced localStorage save).
	const [draftStatus, setDraftStatus] = useState(""); // '', 'saving', 'saved'
	const draftSaveTimerRef = useRef(null);
	const step1BaselineNoteRef = useRef(null);
	const step1DraftAutoRestoreAttemptedRef = useRef(false);
	const step1NoteShellRef = useRef(null);
	const composerUtilitiesRef = useRef(null);
	const [composerUtilitiesOpen, setComposerUtilitiesOpen] = useState(false);
	const [step1NoteExpanded, setStep1NoteExpanded] = useState(false);
	const draftStorageKey = useMemo(() => {
		const identity = user?.id || user?.email || "guest";
		return `eb-draft-step1-note:${identity}`;
	}, [user?.email, user?.id]);

	useEffect(() => {
		// Keep composer utilities closed when leaving Step 1.
		if (errandStep === 1) return;
		setComposerUtilitiesOpen(false);
		setStep1NoteExpanded(false);
	}, [errandStep]);

	useEffect(() => {
		// Reset per-session baseline + auto-restore state when leaving Step 1.
		if (errandStep === 1) return;
		step1BaselineNoteRef.current = null;
		step1DraftAutoRestoreAttemptedRef.current = false;
	}, [errandStep]);

	useEffect(() => {
		if (typeof window === "undefined") return undefined;
		if (errandStep !== 1 || !step1NoteExpanded) return undefined;

		const handlePointerDownOutside = (event) => {
			const shell = step1NoteShellRef.current;
			const target = event.target;
			if (!shell || !target || shell.contains(target)) return;
			setStep1NoteExpanded(false);
		};

		document.addEventListener("mousedown", handlePointerDownOutside);
		document.addEventListener("touchstart", handlePointerDownOutside);

		return () => {
			document.removeEventListener("mousedown", handlePointerDownOutside);
			document.removeEventListener("touchstart", handlePointerDownOutside);
		};
	}, [errandStep, step1NoteExpanded]);

	useEffect(() => {
		if (typeof window === "undefined") return;
		if (errandStep !== 1) return;

		// Capture a "baseline" note for this Step 1 session so Reset can return to it,
		// while keeping the persisted draft in storage intact.
		if (step1BaselineNoteRef.current === null) {
			step1BaselineNoteRef.current = note || "";
			return;
		}

		// If the user clears the note completely, treat that as a new baseline.
		if (!note || note.trim().length === 0) {
			step1BaselineNoteRef.current = "";
		}
	}, [errandStep, note]);

	useEffect(() => {
		if (typeof window === "undefined") return;
		// Restore draft only when Step 1 opens and the note is empty-ish.
		if (errandStep !== 1) return;
		if (step1DraftAutoRestoreAttemptedRef.current) return;
		step1DraftAutoRestoreAttemptedRef.current = true;
		if (note?.trim?.().length) return;
		try {
			const saved = localStorage.getItem(draftStorageKey);
			if (saved?.trim?.()) {
				const trimmed = saved.trim();
				// If the user lands on Step 1 with an empty note, restoring should also
				// establish the "session baseline" so the Reset button behaves predictably.
				if (step1BaselineNoteRef.current === null) {
					step1BaselineNoteRef.current = trimmed;
				}
				setNote(trimmed);
				setDraftStatus("saved");
			}
		} catch {
			// ignore
		}
	}, [draftStorageKey, errandStep, note]);

	useEffect(() => {
		if (typeof window === "undefined") return;
		if (errandStep !== 1) return;

		if (draftSaveTimerRef.current) {
			window.clearTimeout(draftSaveTimerRef.current);
			draftSaveTimerRef.current = null;
		}

		// Don't spam storage for tiny/empty notes.
		if (!note || note.trim().length < 2) {
			setDraftStatus("");
			return;
		}

		setDraftStatus("saving");
		draftSaveTimerRef.current = window.setTimeout(() => {
			try {
				localStorage.setItem(draftStorageKey, note);
				setDraftStatus("saved");
			} catch {
				setDraftStatus("");
			}
		}, 600);

		return () => {
			if (draftSaveTimerRef.current) {
				window.clearTimeout(draftSaveTimerRef.current);
				draftSaveTimerRef.current = null;
			}
		};
	}, [draftStorageKey, errandStep, note]);

	const handleTitleChange = useCallback(
		(value) => {
			const nextValue = value.slice(0, 200);
			setTitle(nextValue);
			if (!nextValue.trim()) {
				return;
			}

			if (templateAutoMatchDisabledRef.current) {
				return;
			}

			loadTemplateData().then((data) => {
				if (templateAutoMatchDisabledRef.current) {
					return;
				}
				const matchedTemplate = scoreTemplateFromTitle(
					nextValue,
					data.TEMPLATE_KEYWORDS || {},
				);
				if (matchedTemplate && matchedTemplate !== template) {
					latestTemplateRef.current = matchedTemplate;
					setTemplate(matchedTemplate);
					setTemplateJustChanged(true);
					setTimeout(() => setTemplateJustChanged(false), 2000);
					const currentSuggestion = getTemplateSuggestionSync(template);
					if (!note.trim() || note === (currentSuggestion || "")) {
						const nextNote = (
							data.TEMPLATE_SUGGESTIONS?.[matchedTemplate] || ""
						).trim();
						setNote(nextNote);
						lastTemplateAutofillNoteRef.current = nextNote;
					}
				}
			});
		},
		[
			getTemplateSuggestionSync,
			loadTemplateData,
			note,
			scoreTemplateFromTitle,
			template,
		],
	);

	const applyTemplatePayload = useCallback(
		(payload = {}) => {
			const nextTitle = (payload.title || "").slice(0, 200);
			if (payload.template) {
				templateAutoMatchDisabledRef.current = true;
				setTitle(nextTitle);
			} else {
				handleTitleChange(nextTitle);
			}

			if (payload.template) {
				latestTemplateRef.current = payload.template;
				templateAutoMatchDisabledRef.current = false;
				setTemplate(payload.template);
				setTemplateJustChanged(true);
				setTimeout(() => setTemplateJustChanged(false), 2000);
			}

			setNote(payload.note || "");
			setSensitivity(
				payload.sensitivity || "Sensitive (documents, money, medicine)",
			);
			setPickup(payload.pickup || "");
			setDropoff(payload.dropoff || "");
			setPickupTimeSlotDate(payload.pickupTimeSlotDate || "");
			setPickupTimeSlotStart(payload.pickupTimeSlotStart || "");
			setPickupTimeSlotEnd(payload.pickupTimeSlotEnd || "");
			setErrandStep(1);
		},
		[handleTitleChange],
	);

	const handleSaveTemplate = useCallback(() => {
		const trimmedTitle = title.trim();
		const trimmedNote = note.trim();
		if (!trimmedTitle && !trimmedNote) {
			showActionToast("Add a title or note before saving a template.", {
				type: "warning",
			});
			return;
		}
		const name =
			savedTemplateName.trim() ||
			trimmedTitle ||
			formatTemplateTitle(template) ||
			"Saved template";
		const newTemplate = {
			id: `${Date.now()}-${Math.random().toString(36).slice(2, 7)}`,
			name,
			title: trimmedTitle,
			template,
			note: note,
			sensitivity,
			pickup,
			dropoff,
			pickupTimeSlotDate,
			pickupTimeSlotStart,
			pickupTimeSlotEnd,
			createdAt: new Date().toISOString(),
		};
		setSavedTemplates((prev) => {
			const next = [newTemplate, ...prev].slice(0, 8);
			return next;
		});
		setSavedTemplateName("");
		showActionToast(`Template saved: ${name}`, { type: "success" });
	}, [
		dropoff,
		note,
		pickup,
		pickupTimeSlotDate,
		pickupTimeSlotEnd,
		pickupTimeSlotStart,
		savedTemplateName,
		sensitivity,
		showActionToast,
		template,
		title,
	]);

	const handleApplySavedTemplate = useCallback(
		(savedTemplate) => {
			if (!savedTemplate) return;
			applyTemplatePayload({
				title: savedTemplate.title,
				template: savedTemplate.template,
				note: savedTemplate.note,
				sensitivity: savedTemplate.sensitivity,
				pickup: savedTemplate.pickup,
				dropoff: savedTemplate.dropoff,
				pickupTimeSlotDate: savedTemplate.pickupTimeSlotDate,
				pickupTimeSlotStart: savedTemplate.pickupTimeSlotStart,
				pickupTimeSlotEnd: savedTemplate.pickupTimeSlotEnd,
			});
			showActionToast(`Loaded template: ${savedTemplate.name}`, {
				type: "success",
			});
		},
		[applyTemplatePayload, showActionToast],
	);

	const handleDeleteSavedTemplate = useCallback(
		(templateId) => {
			setSavedTemplates((prev) =>
				prev.filter((item) => item.id !== templateId),
			);
			showActionToast("Template removed.", { type: "info" });
		},
		[showActionToast],
	);

	const handleRepeatErrand = useCallback(
		(errand) => {
			if (!errand) return;
			applyTemplatePayload({
				title: errand.title,
				note: errand.note,
				sensitivity: errand.sensitivity,
				pickup: errand.pickupLocation,
				dropoff: errand.dropoffLocation,
				pickupTimeSlotDate: errand.pickupTimeSlotDate,
				pickupTimeSlotStart: errand.pickupTimeSlotStart,
				pickupTimeSlotEnd: errand.pickupTimeSlotEnd,
			});
			showActionToast("Loaded details from a recent errand.", {
				type: "success",
			});
		},
		[applyTemplatePayload, showActionToast],
	);

	// Location autocomplete functions
	const handlePickupInput = (value) => {
		setPickup(value);
		if (value.length > 1) {
			const query = value.toLowerCase();
			if (appDataRef.current?.COMMON_LOCATIONS) {
				const filtered = appDataRef.current.COMMON_LOCATIONS.filter((loc) =>
					loc.toLowerCase().includes(query),
				);
				setPickupSuggestions(filtered.slice(0, 5));
				setShowPickupSuggestions(filtered.length > 0);
			} else {
				loadAppData().then((data) => {
					const filtered = (data.COMMON_LOCATIONS || []).filter((loc) =>
						loc.toLowerCase().includes(query),
					);
					setPickupSuggestions(filtered.slice(0, 5));
					setShowPickupSuggestions(filtered.length > 0);
				});
			}
		} else {
			setPickupSuggestions([]);
			setShowPickupSuggestions(false);
		}
	};

