	const fetchWithTimeout = useCallback(
		async (url, options = {}, config = {}) => {
			const { timeoutMs = 30000, retries = 1, retryDelayMs = 1000 } = config;
			let lastError = null;
			const fallbackUrl = getCapacitorLoopbackFallbackUrl(
				url,
				capacitorPlatform,
			);
			const requestUrls = fallbackUrl && fallbackUrl !== url ? [url, fallbackUrl] : [url];
			const shouldUseNativeHttp =
				Boolean(capacitorPlatform) &&
				Boolean(isCapacitor) &&
				Boolean(window?.Capacitor?.isNativePlatform?.());

			const asResponseLike = (nativeResponse) => {
				const status = Number(nativeResponse?.status ?? 0);
				const headersObj = nativeResponse?.headers || {};
				const lowerHeaders = {};
				try {
					for (const [key, value] of Object.entries(headersObj)) {
						lowerHeaders[String(key).toLowerCase()] = value;
					}
				} catch {
					// ignore
				}
				const data = nativeResponse?.data;
				return {
					ok: status >= 200 && status < 300,
					status,
					headers: {
						get: (name) =>
							lowerHeaders[String(name || "").toLowerCase()] ?? null,
					},
					json: async () => {
						if (data == null) return null;
						if (typeof data === "object") return data;
						try {
							return JSON.parse(String(data));
						} catch {
							return data;
						}
					},
					text: async () => {
						if (data == null) return "";
						if (typeof data === "string") return data;
						try {
							return JSON.stringify(data);
						} catch {
							return String(data);
						}
					},
				};
			};

			const nativeRequest = async (requestUrl) => {
				const method = String(options?.method || "GET").toUpperCase();
				const headers = options?.headers || {};
				let data = options?.body;
				let contentType;
				try {
					contentType =
						typeof headers?.get === "function"
							? headers.get("content-type") || headers.get("Content-Type")
							: headers?.["Content-Type"] || headers?.["content-type"];
				} catch {
					contentType = undefined;
				}
				if (
					typeof data === "string" &&
					String(contentType || "").toLowerCase().includes("application/json")
				) {
					try {
						data = JSON.parse(data);
					} catch {
						// keep string
					}
				}
				const work = CapacitorHttp.request({
					url: requestUrl,
					method,
					headers,
					data,
				});
				return asResponseLike(
					await Promise.race([
						work,
						new Promise((_, reject) =>
							setTimeout(() => reject(new Error("Request timeout")), timeoutMs),
						),
					]),
				);
			};

			for (let attempt = 0; attempt <= retries; attempt += 1) {
				for (const requestUrl of requestUrls) {
					if (shouldUseNativeHttp) {
						try {
							return await nativeRequest(requestUrl);
						} catch (err) {
							lastError = err;
							const isNetwork =
								err?.name === "TypeError" ||
								String(err?.message || "").toLowerCase().includes("network") ||
								String(err?.message || "").toLowerCase().includes("timeout");
							if (attempt < retries && isNetwork) {
								await new Promise((resolve) => setTimeout(resolve, retryDelayMs));
								break;
							}
							throw err;
						}
					}

					const controller = new AbortController();
					const timeoutId = setTimeout(() => controller.abort(), timeoutMs);

					try {
						const response = await fetch(requestUrl, {
							...options,
							signal: controller.signal,
						});
						clearTimeout(timeoutId);
						return response;
					} catch (err) {
						clearTimeout(timeoutId);
						lastError = err;
						const isAbort = err?.name === "AbortError";
						const isNetwork = err?.name === "TypeError";
						const shouldTryAlternateUrl =
							requestUrl !== requestUrls[requestUrls.length - 1] && (isAbort || isNetwork);
						if (shouldTryAlternateUrl) {
							console.warn("[NETWORK] Primary request failed, retrying alternate loopback host", {
								from: requestUrl,
								to: requestUrls[requestUrls.length - 1],
								error: err?.message,
							});
							continue;
						}
						if (attempt < retries && (isAbort || isNetwork)) {
							await new Promise((resolve) => setTimeout(resolve, retryDelayMs));
							break;
						}
						throw err;
					}
				}
			}

			throw lastError || new Error("Request failed");
		},
		[capacitorPlatform],
	);

	// GraphQL-based auth function (more reliable than REST endpoints)
	async function graphqlAuth(isLogin) {
		const loginMutation = `mutation Login($email: String!, $password: String!, $role: String!) {
      login(input: { email: $email, password: $password, role: $role }) {
        accessToken userId email firstName lastName phone addressLine1 addressLine2 city state postalCode country isEmailVerified isAdmin
      }
    }`;
		const signupMutation = `mutation Signup(
      $email: String!
      $password: String!
      $firstName: String
      $lastName: String
      $phone: String
      $addressLine1: String
      $addressLine2: String
      $city: String
      $state: String
      $postalCode: String
      $country: String
      $otpDeliveryChannel: String
      $otpDeliveryMode: String
      $role: String
    ) {
      signup(input: {
        email: $email
        password: $password
        firstName: $firstName
        lastName: $lastName
        phone: $phone
        addressLine1: $addressLine1
        addressLine2: $addressLine2
        city: $city
        state: $state
        postalCode: $postalCode
        country: $country
        otpDeliveryChannel: $otpDeliveryChannel
        otpDeliveryMode: $otpDeliveryMode
        role: $role
      }) {
        accessToken userId email firstName lastName phone addressLine1 addressLine2 city state postalCode country isEmailVerified isAdmin
      }
    }`;
		const mutation = isLogin ? loginMutation : signupMutation;
		const variables = isLogin
			? {
				email: authEmail,
				password: authPassword,
				role: "client",
			}
			: {
				email: authEmail,
				password: authPassword,
				firstName: authFirstName || null,
				lastName: authLastName || null,
				phone: authPhone || null,
				addressLine1: authAddressLine || null,
				addressLine2: authAddressLine2 || null,
				city: authCity || null,
				state: null,
				postalCode: authPostcode || null,
				country: authCountry || null,
				otpDeliveryChannel,
				otpDeliveryMode,
				role: "client",
			};

		console.log(
			`[AUTH] Calling GraphQL ${isLogin ? "login" : "signup"} mutation`,
		);
		console.log(`[AUTH] API_BASE_URL: ${API_BASE_URL}`);
		console.log(`[AUTH] Email: ${isLogin ? authEmail : authEmail}`);

		try {
			const fullUrl = `${API_BASE_URL}/graphql`;
			const body = JSON.stringify({ query: mutation, variables });

			console.log(`[AUTH] Fetching from: ${fullUrl}`);

			// Standard fetch - iOS simulator should handle this
			const res = await fetchWithTimeout(
				fullUrl,
				{
					method: "POST",
					headers: { "Content-Type": "application/json" },
					body,
				},
				{
					timeoutMs: 30000,
					retries: 1,
					retryDelayMs: 1200,
				},
			);
			console.log(`[AUTH] Fetch response received, status: ${res.status}`);

			if (!res.ok) {
				const errorText = await res.text();
				console.error("[AUTH] HTTP error response:", errorText);
				throw new Error(`HTTP ${res.status}: ${errorText}`);
			}

			const result = await res.json();
			console.log("[AUTH] GraphQL response:", result);

			if (result.errors && result.errors.length > 0) {
				throw new Error(result.errors[0].message || "Authentication failed");
			}

			const authData = isLogin ? result.data.login : result.data.signup;
			if (!authData) {
				throw new Error("No auth data returned");
			}

			return authData;
		} catch (err) {
			const normalizedMessage = (err?.message || "").toLowerCase();
			const expectedAuthError =
				normalizedMessage.includes("email not verified") ||
				normalizedMessage.includes("pending verification") ||
				normalizedMessage.includes("verify your email") ||
				normalizedMessage.includes("invalid email or password") ||
				normalizedMessage.includes("invalid credentials") ||
				normalizedMessage.includes("wrong password") ||
				normalizedMessage.includes("user not found") ||
				normalizedMessage.includes("not registered");
			if (expectedAuthError) {
				console.info("[AUTH] Expected auth error:", err.message);
			} else {
				console.error("[AUTH] Error caught in graphqlAuth");
				console.error("[AUTH] Error type:", err.constructor.name);
				console.error("[AUTH] Error name:", err.name);
				console.error("[AUTH] Error message:", err.message);
				console.error("[AUTH] Error code:", err.code);
				console.error("[AUTH] Stack:", err.stack);
			}

			if (err.name === "AbortError") {
				throw new Error(
					"Request timeout. Please check your connection and try again.",
				);
			}
			throw err;
		}
	}

	const restSignup = async () => {
		const payload = {
			email: authEmail,
			password: authPassword,
			first_name: authFirstName || null,
			last_name: authLastName || null,
			phone: authPhone || null,
			address_line1: authAddressLine || null,
			address_line2: authAddressLine2 || null,
			city: authCity || null,
			state: null,
			postal_code: authPostcode || null,
			country: authCountry || null,
			otp_delivery_channel: otpDeliveryChannel,
			otp_delivery_mode: otpDeliveryMode,
			role: "client",
		};

		const res = await fetchWithTimeout(
			`${API_BASE_URL}/auth/signup`,
			{
				method: "POST",
				headers: { "Content-Type": "application/json" },
				body: JSON.stringify(payload),
			},
			{
				timeoutMs: 30000,
				retries: 1,
				retryDelayMs: 1200,
			},
		);

		const data = await res.json().catch(() => ({}));
		if (!res.ok) {
			throw new Error(data?.detail || "Signup failed. Please try again.");
		}

		if (!data?.access_token || !data?.user_id) {
			throw new Error("Signup failed. No access token returned.");
		}

		return {
			accessToken: data.access_token,
			userId: data.user_id,
			email: data.email || authEmail,
			firstName: data.first_name,
			lastName: data.last_name,
			phone: data.phone,
			isEmailVerified: data.is_email_verified,
			isAdmin: data.is_admin,
		};
	};

	const graphqlLoginWithCredentials = useCallback(
		async (email, password) => {
			const mutation = `mutation Login($email: String!, $password: String!, $role: String!) {
      login(input: { email: $email, password: $password, role: $role }) {
        accessToken userId email firstName lastName phone addressLine1 addressLine2 city state postalCode country isEmailVerified isAdmin
      }
    }`;

			const res = await fetchWithTimeout(
				`${API_BASE_URL}/graphql`,
				{
					method: "POST",
					headers: { "Content-Type": "application/json" },
					body: JSON.stringify({
						query: mutation,
						variables: { email, password, role: "client" },
					}),
				},
				{
					timeoutMs: 30000,
					retries: 1,
					retryDelayMs: 1200,
				},
			);

			if (!res.ok) {
				const errorText = await res.text();
				throw new Error(`HTTP ${res.status}: ${errorText}`);
			}

			const result = await res.json();
			if (result.errors && result.errors.length > 0) {
				throw new Error(result.errors[0].message || "Authentication failed");
			}

			const authData = result.data?.login;
			if (!authData) {
				throw new Error("No auth data returned");
			}

			return authData;
		},
		[fetchWithTimeout],
	);

	// Helper function to switch to signup mode with clean form fields
