	async function handlePurgeUnverifiedCustomers() {
		const confirmed = window.confirm(
			"Delete all unverified accounts? This removes every user that has not verified their email.",
		);
		if (!confirmed) return;

		try {
			const token = localStorage.getItem("authToken") || cache.getAuthToken();
			if (!token) {
				alert("Not authenticated");
				return;
			}

			const response = await fetch(
				`${API_BASE_URL}/admin/customers/unverified/purge`,
				{
					method: "POST",
					headers: {
						Authorization: `Bearer ${token}`,
					},
				},
			);

			const data = await response.json().catch(() => ({}));
			if (response.ok) {
				setAdminCustomers((prev) =>
					(Array.isArray(prev) ? prev : []).filter(
						(user) => Boolean(user?.is_email_verified) || !user?.email,
					),
				);
				setAdminSelectedCustomerIds([]);
				showActionToast(
					`Deleted ${data.deleted_count || 0} unverified accounts.`,
					{ type: "success" },
				);
			} else {
				showActionToast(
					data.detail || "Failed to delete unverified accounts.",
					{ type: "error" },
				);
			}
		} catch (err) {
			console.error("Error deleting unverified accounts:", err);
			showActionToast("Failed to delete unverified accounts.", {
				type: "error",
			});
		}
	}

	async function handleDeleteCustomer(customer) {
		const userId = customer?.id;
		const email = customer?.email;
		if (!userId) {
			showActionToast("Missing user id.", { type: "error" });
			return;
		}

		const confirmed = window.confirm(
			`Delete this user?\n\nID: ${userId}${email ? `\nEmail: ${email}` : ""}\n\nThis cannot be undone.`,
		);
		if (!confirmed) return;

		try {
			const token = localStorage.getItem("authToken") || cache.getAuthToken();
			if (!token) {
				showActionToast("Not authenticated", { type: "error" });
				return;
			}

			const response = await fetch(`${API_BASE_URL}/admin/users/${userId}`, {
				method: "DELETE",
				headers: {
					Authorization: `Bearer ${token}`,
				},
			});

			const data = await response.json().catch(() => ({}));
			if (response.ok) {
				setAdminCustomers((prev) =>
					(Array.isArray(prev) ? prev : []).filter(
						(existing) => Number(existing?.id) !== Number(userId),
					),
				);
				setAdminSelectedCustomerIds((prev) =>
					(Array.isArray(prev) ? prev : []).filter(
						(id) => Number(id) !== Number(userId),
					),
				);
				showActionToast(
					`Deleted user ${userId}${email ? ` (${email})` : ""}.`,
					{ type: "success" },
				);
				return;
			}

			const detail =
				data?.detail ||
				data?.message ||
				(data && typeof data === "string" ? data : "");
			showActionToast(
				`Delete failed (${response.status}). ${detail || "Please try again."}`,
				{ type: "error" },
			);
		} catch (err) {
			console.error("Error deleting user:", err);
			showActionToast("Failed to delete user. Please try again.", {
				type: "error",
			});
		}
	}

	async function handleBulkDeleteCustomers(selectedIds) {
		const ids = Array.isArray(selectedIds) ? selectedIds : [];
		const normalized = ids
			.map((v) => Number(v))
			.filter((v) => Number.isFinite(v) && v > 0);
		const unique = Array.from(new Set(normalized));
		if (!unique.length) {
			showActionToast("No users selected.", { type: "warning" });
			return;
		}

		const confirmed = window.confirm(
			`Delete ${unique.length} selected user(s)?\n\nThis cannot be undone.`,
		);
		if (!confirmed) return;

		try {
			const token = localStorage.getItem("authToken") || cache.getAuthToken();
			if (!token) {
				showActionToast("Not authenticated", { type: "error" });
				return;
			}

			const response = await fetch(`${API_BASE_URL}/admin/users/bulk-delete`, {
				method: "POST",
				headers: {
					"Content-Type": "application/json",
					Authorization: `Bearer ${token}`,
				},
				body: JSON.stringify({ user_ids: unique }),
			});

			const data = await response.json().catch(() => ({}));
			if (!response.ok) {
				const detail =
					data?.detail ||
					data?.message ||
					(data && typeof data === "string" ? data : "");
				showActionToast(
					`Bulk delete failed (${response.status}). ${detail || ""}`.trim(),
					{ type: "error" },
				);
				return;
			}

			const requested = Number(data.requested || unique.length);
			const deletedCountFromBackend = Number(data.deleted || 0);
			const deletedIds = (Array.isArray(data.deleted_user_ids) ? data.deleted_user_ids : [])
				.map((v) => Number(v))
				.filter((v) => Number.isFinite(v) && v > 0);
			const skippedAdminEmails = Array.isArray(data.skipped_admins)
				? data.skipped_admins.filter(Boolean)
				: [];
			const skippedIds = (Array.isArray(data.skipped_user_ids) ? data.skipped_user_ids : [])
				.map((v) => Number(v))
				.filter((v) => Number.isFinite(v) && v > 0);
			const failedIds = (Array.isArray(data.failed_user_ids) ? data.failed_user_ids : [])
				.map((v) => Number(v))
				.filter((v) => Number.isFinite(v) && v > 0);
			const notFoundIds = (Array.isArray(data.not_found) ? data.not_found : [])
				.map((v) => Number(v))
				.filter((v) => Number.isFinite(v) && v > 0);

			const deleted = deletedIds.length ? deletedIds.length : deletedCountFromBackend;

			const canAssumeAllDeleted =
				!deletedIds.length &&
				deleted > 0 &&
				deleted === requested &&
				!data.skipped_self &&
				!skippedAdminEmails.length &&
				!skippedIds.length &&
				!failedIds.length &&
				!notFoundIds.length;
			const idsToRemove = deletedIds.length ? deletedIds : canAssumeAllDeleted ? unique : [];

			const warningBits = [];
			if (data.skipped_self) warningBits.push("Skipped your own admin account");
			if (skippedAdminEmails.length)
				warningBits.push(
					`Skipped ${skippedAdminEmails.length} admin account(s) (requires elevated admin)`,
				);
			if (failedIds.length) warningBits.push(`${failedIds.length} failed (constraints)`);
			if (notFoundIds.length) warningBits.push(`${notFoundIds.length} not found`);

			let msg = `Deleted ${deleted} of ${requested} selected user(s).`;
			if (warningBits.length) msg += ` ${warningBits.join(" · ")}.`;

			const toastType = deleted === 0 || warningBits.length ? "warning" : "success";
			showActionToast(msg, { type: toastType });

			if (idsToRemove.length) {
				setAdminCustomers((prev) =>
					(Array.isArray(prev) ? prev : []).filter(
						(user) => !idsToRemove.includes(Number(user?.id)),
					),
				);
				setAdminSelectedCustomerIds((prev) =>
					(Array.isArray(prev) ? prev : []).filter(
						(id) => !idsToRemove.includes(Number(id)),
					),
				);
			}
		} catch (err) {
			console.error("Error bulk deleting users:", err);
			showActionToast("Failed to bulk delete users.", { type: "error" });
		}
	}

	async function handleDownloadPilotDocument(documentId, filename) {
		try {
			const token = localStorage.getItem("authToken") || cache.getAuthToken();
			if (!token) {
				alert("Not authenticated");
				return;
			}

			const response = await fetch(
				`${API_BASE_URL}/admin/pilot-documents/${documentId}/download`,
				{
					headers: {
						Authorization: `Bearer ${token}`,
					},
				},
			);

			if (!response.ok) {
				const data = await response.json().catch(() => ({}));
				alert(`Error: ${data.detail || "Failed to download document"}`);
				return;
			}

			const blob = await response.blob();
			const url = window.URL.createObjectURL(blob);
			const link = document.createElement("a");
			link.href = url;
			link.download = filename || "document";
			document.body.appendChild(link);
			link.click();
			window.URL.revokeObjectURL(url);
			document.body.removeChild(link);
		} catch (err) {
			console.error("Error downloading pilot document:", err);
			alert("Failed to download document.");
		}
	}

