	const activeErrandsCount = useMemo(() => {
		if (!Array.isArray(errands)) return 0;
		return errands.filter((errand) => {
			const statusKey = normalizeStatusKey(errand.status);
			if (!statusKey) return true;
			return !completedStatusKeys.has(statusKey);
		}).length;
	}, [completedStatusKeys, errands, normalizeStatusKey]);

	const completedThisMonthCount = useMemo(() => {
		if (!Array.isArray(errands)) return 0;
		const cutoff = Date.now() - 30 * 24 * 60 * 60 * 1000;
		return errands.filter((errand) => {
			const history = Array.isArray(errand.history) ? errand.history : [];
			const completedEntry = [...history].reverse().find((entry) => {
				const entryKey = normalizeStatusKey(entry.newStatus || entry.oldStatus);
				return entryKey && completedStatusKeys.has(entryKey);
			});
			const completedAt = completedEntry?.createdAt
				? new Date(completedEntry.createdAt).getTime()
				: null;
			if (completedAt && !Number.isNaN(completedAt)) {
				return completedAt >= cutoff;
			}
			const statusKey = normalizeStatusKey(errand.status);
			if (statusKey && completedStatusKeys.has(statusKey)) {
				const createdAt = errand.createdAt
					? new Date(errand.createdAt).getTime()
					: null;
				return createdAt && !Number.isNaN(createdAt)
					? createdAt >= cutoff
					: false;
			}
			return false;
		}).length;
	}, [completedStatusKeys, errands, normalizeStatusKey]);

