										if (trackingRouteMeta?.kind === "tracking") {
											const fallback = user
												? (userIsAdmin ? ROUTE_ADMIN : ROUTE_CLIENT_ERRANDS)
												: ROUTE_HOME;
											navigateBackOr(fallback);
											return;
										}
										navigateBackOr(buildClientErrandPath(currentTrackingRouteErrandId));
